#!/usr/bin/env node

// src/index.ts
import { Command } from "commander";

// src/commands/add.ts
import pc from "picocolors";

// src/config.ts
import fs from "fs-extra";
import path from "path";
var CONFIG_FILE = "forge.config.json";
var ASCII_KEY = "ascii-components";
async function readConfig() {
  const configPath = path.join(process.cwd(), CONFIG_FILE);
  if (!await fs.pathExists(configPath)) return null;
  const full = await fs.readJson(configPath);
  return full[ASCII_KEY] ?? null;
}
async function writeConfig(config) {
  const configPath = path.join(process.cwd(), CONFIG_FILE);
  const full = await fs.pathExists(configPath) ? await fs.readJson(configPath) : {};
  full[ASCII_KEY] = config;
  await fs.writeJson(configPath, full, { spaces: 2 });
}
function createDefaultConfig() {
  return {
    output: "components/forge",
    components: {}
  };
}

// src/registry.ts
var REGISTRY = [
  {
    id: "ascii",
    displayName: "ForgeAscii",
    description: "Image to animated ASCII art - 4 character sets, 5 animations"
  }
];
var REGISTRY_BY_ID = Object.fromEntries(
  REGISTRY.map((c) => [c.id, c])
);

// src/generate.ts
import fs2 from "fs-extra";
import path2 from "path";

// src/generators/ascii.ts
var RAMPS = {
  standard: " .,:;+*?%S#@",
  block: " \u2591\u2592\u2593\u2588",
  braille: " \u2802\u2806\u2816\u2836\u2837\u283F\u287F\u28FF",
  minimal: " .:|="
};
var ANIMATION_KEYFRAMES = `@keyframes forge-ascii-fadein {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes forge-ascii-scanline {
  from { clip-path: inset(0 0 100% 0); }
  to { clip-path: inset(0 0 0 0); }
}

@keyframes forge-ascii-flicker {
  0%, 100% { opacity: 1; }
  8% { opacity: 0.4; }
  18% { opacity: 0.9; }
  29% { opacity: 0.5; }
  41% { opacity: 1; }
  53% { opacity: 0.6; }
  67% { opacity: 0.95; }
  78% { opacity: 0.45; }
  89% { opacity: 1; }
}

@keyframes forge-ascii-wave {
  0%, 100% { transform: translateY(0); }
  25% { transform: translateY(-6px); }
  50% { transform: translateY(0); }
  75% { transform: translateY(6px); }
}

@keyframes forge-ascii-glitch {
  0%, 100% { transform: translate(0, 0); text-shadow: none; }
  20% { transform: translate(-2px, 1px); text-shadow: -2px 0 var(--forge-ascii-color), 2px 0 #e24b4a; }
  40% { transform: translate(2px, -1px); text-shadow: 2px 0 #378ADD, -2px 0 var(--forge-ascii-color); }
  60% { transform: translate(-1px, 0); text-shadow: -1px 0 var(--forge-ascii-color), 1px 0 #e24b4a; }
  80% { transform: translate(1px, 0); text-shadow: none; }
}`;
var ANIMATION_SHORTHAND = {
  fadein: "forge-ascii-fadein {{duration}}ms ease-out forwards",
  scanline: "forge-ascii-scanline {{duration}}ms steps(24, end) forwards",
  flicker: "forge-ascii-flicker {{duration}}ms linear infinite",
  wave: "forge-ascii-wave {{duration}}ms ease-in-out infinite",
  glitch: "forge-ascii-glitch {{duration}}ms steps(6, end) infinite"
};
function generateAscii(props) {
  const color = props.color ?? "#EF9F27";
  const density = props.density ?? 80;
  const characterSet = props.characterSet ?? "standard";
  const animation = props.animation ?? "fadein";
  const duration = props.duration ?? 1200;
  const ramp = RAMPS[characterSet] ?? RAMPS.standard;
  const tsx = `// ForgeAscii - generated by forge-ascii CLI
// Edit this file freely - you own it.
// Re-generate with: npx @forgelabs-studio/ascii update ascii
// Converts an uploaded PNG/JPG into ASCII art rendered as plain text.
// Runs synchronously on the main thread - fine for the kind of image sizes
// a person uploads by hand; resize very large images before converting if
// you need this on a hot path.

import { useRef, useState } from 'react'
import './ForgeAscii.css'

type CharacterSet = 'standard' | 'block' | 'braille' | 'minimal'
type AsciiAnimation = 'none' | 'fadein' | 'scanline' | 'flicker' | 'wave' | 'glitch'

const RAMPS: Record<CharacterSet, string> = {
  standard: ' .,:;+*?%S#@',
  block: ' \u2591\u2592\u2593\u2588',
  braille: ' \u2802\u2806\u2816\u2836\u2837\u283F\u287F\u28FF',
  minimal: ' .:|=',
}

const ACCEPTED_TYPES = ['image/png', 'image/jpeg']

function brightnessToChar(brightness: number, ramp: string): string {
  const index = Math.min(ramp.length - 1, Math.floor((brightness / 255) * ramp.length))
  return ramp[index]
}

function convertToAscii(imageData: ImageData, density: number, ramp: string): string {
  const { width, height, data } = imageData
  const cols = Math.max(1, Math.min(200, Math.round(density)))
  const rows = Math.max(1, Math.round((height / width) * cols * 0.5))
  const cellWidth = width / cols
  const cellHeight = height / rows

  const lines: string[] = new Array(rows)
  for (let row = 0; row < rows; row++) {
    const yStart = Math.floor(row * cellHeight)
    const yEnd = Math.max(yStart + 1, Math.floor((row + 1) * cellHeight))

    let line = ''
    for (let col = 0; col < cols; col++) {
      const xStart = Math.floor(col * cellWidth)
      const xEnd = Math.max(xStart + 1, Math.floor((col + 1) * cellWidth))

      let total = 0
      let count = 0
      for (let y = yStart; y < yEnd; y++) {
        for (let x = xStart; x < xEnd; x++) {
          const i = (y * width + x) * 4
          total += data[i] * 0.299 + data[i + 1] * 0.587 + data[i + 2] * 0.114
          count++
        }
      }
      line += brightnessToChar(count > 0 ? total / count : 0, ramp)
    }
    lines[row] = line
  }

  return lines.join('\\n')
}

interface ForgeAsciiProps {
  color?: string
  density?: number
  characterSet?: CharacterSet
  animation?: AsciiAnimation
  duration?: number
}

export function ForgeAscii({
  color = '${color}',
  density = ${density},
  characterSet = '${characterSet}',
  animation = '${animation}',
  duration = ${duration},
}: ForgeAsciiProps) {
  const [asciiText, setAsciiText] = useState('')
  const [fileName, setFileName] = useState('')
  const [status, setStatus] = useState<'idle' | 'converting' | 'ready' | 'error'>('idle')
  const [dragOver, setDragOver] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)

  function handleFiles(files: FileList | null) {
    const file = files?.[0]
    if (!file || !ACCEPTED_TYPES.includes(file.type)) return

    setFileName(file.name)
    setStatus('converting')

    const img = new Image()
    img.onload = () => {
      const canvas = document.createElement('canvas')
      canvas.width = img.naturalWidth
      canvas.height = img.naturalHeight
      const ctx = canvas.getContext('2d')
      if (!ctx) {
        setStatus('error')
        return
      }
      ctx.drawImage(img, 0, 0)

      try {
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height)
        setAsciiText(convertToAscii(imageData, density, RAMPS[characterSet] ?? RAMPS.standard))
        setStatus('ready')
      } catch {
        setStatus('error')
      } finally {
        URL.revokeObjectURL(img.src)
      }
    }
    img.onerror = () => setStatus('error')
    img.src = URL.createObjectURL(file)
  }

  function handleRemoveImage() {
    setAsciiText('')
    setFileName('')
    setStatus('idle')
    if (inputRef.current) inputRef.current.value = ''
  }

  return (
    <div
      className="forge-ascii-wrap"
      style={{ '--forge-ascii-color': color, '--forge-ascii-duration': \`\${duration}ms\` } as React.CSSProperties}
    >
      <div
        className={\`forge-ascii-drop\${dragOver ? ' forge-ascii-drop--over' : ''}\`}
        onDragOver={(e) => { e.preventDefault(); setDragOver(true) }}
        onDragLeave={() => setDragOver(false)}
        onDrop={(e) => {
          e.preventDefault()
          setDragOver(false)
          handleFiles(e.dataTransfer.files)
        }}
        onClick={() => inputRef.current?.click()}
      >
        {asciiText ? (
          <pre className={\`forge-ascii\${animation !== 'none' ? \` forge-ascii--\${animation}\` : ''}\`}>
            {asciiText}
          </pre>
        ) : (
          <span className="forge-ascii-hint">
            {status === 'error' ? 'Could not read that file - try another PNG or JPG' : 'Click or drop a PNG / JPG'}
          </span>
        )}
        <input
          ref={inputRef}
          type="file"
          accept="image/png,image/jpeg"
          onChange={(e) => handleFiles(e.target.files)}
          style={{ display: 'none' }}
        />
      </div>
      {fileName && (
        <div className="forge-ascii-filename">
          {fileName} - {status}
          <button type="button" className="forge-ascii-remove" onClick={handleRemoveImage} aria-label="Remove image" title="Remove image">
            \xD7
          </button>
        </div>
      )}
    </div>
  )
}
`;
  const animationCss = Object.entries(ANIMATION_SHORTHAND).map(([id, shorthand]) => `.forge-ascii--${id} {
  animation: ${shorthand.replace("{{duration}}", "var(--forge-ascii-duration)")};
}`).join("\n\n");
  const css = `/* ForgeAscii.css - generated by forge-ascii CLI */
/* Glyph ramp baked in at generation time (${characterSet}): ${ramp} */

.forge-ascii-wrap {
  display: inline-block;
}

.forge-ascii-drop {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 200px;
  min-height: 120px;
  padding: 16px;
  background: #09090b;
  border: 1px dashed rgba(255,255,255,0.15);
  border-radius: 8px;
  cursor: pointer;
  transition: border-color 0.12s, background 0.12s;
}

.forge-ascii-drop--over {
  border-color: var(--forge-ascii-color);
  background: rgba(255,255,255,0.03);
}

.forge-ascii-hint {
  font-family: Inter, sans-serif;
  font-size: 12px;
  color: rgba(240,237,232,0.4);
}

.forge-ascii-filename {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 6px;
  font-family: 'DM Mono', ui-monospace, monospace;
  font-size: 11px;
  color: rgba(240,237,232,0.4);
}

.forge-ascii-remove {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  padding: 0;
  border: none;
  border-radius: 4px;
  background: transparent;
  color: inherit;
  font-size: 13px;
  line-height: 1;
  cursor: pointer;
}

.forge-ascii {
  margin: 0;
  color: var(--forge-ascii-color);
  font-family: 'DM Mono', ui-monospace, monospace;
  font-size: 8px;
  line-height: 1.1;
  white-space: pre;
}
${ANIMATION_KEYFRAMES}
${animationCss}
@media (prefers-reduced-motion: reduce) {
  .forge-ascii {
    animation: none !important;
  }
}
`;
  return { tsx, css };
}

// src/generate.ts
var GENERATORS = {
  ascii: generateAscii
};
async function generateComponent(componentId, displayName, props, config) {
  const generator = GENERATORS[componentId];
  if (!generator) throw new Error(`No generator found for component: ${componentId}`);
  const { tsx, css } = generator(props);
  const outputDir = path2.join(process.cwd(), config.output);
  await fs2.ensureDir(outputDir);
  await fs2.writeFile(path2.join(outputDir, `${displayName}.tsx`), tsx, "utf8");
  await fs2.writeFile(path2.join(outputDir, `${displayName}.css`), css, "utf8");
}

// src/manifest.ts
import fs3 from "fs-extra";
import path3 from "path";
var MANIFEST_FILE = ".forge.json";
var ASCII_KEY2 = "ascii-components";
async function readManifest() {
  const manifestPath = path3.join(process.cwd(), MANIFEST_FILE);
  if (!await fs3.pathExists(manifestPath)) return {};
  const full = await fs3.readJson(manifestPath);
  return full[ASCII_KEY2] ?? {};
}
async function writeManifest(manifest) {
  const manifestPath = path3.join(process.cwd(), MANIFEST_FILE);
  const full = await fs3.pathExists(manifestPath) ? await fs3.readJson(manifestPath) : {};
  full[ASCII_KEY2] = manifest;
  await fs3.writeJson(manifestPath, full, { spaces: 2 });
}
async function setComponentVersion(componentId, version) {
  const manifest = await readManifest();
  manifest[componentId] = version;
  await writeManifest(manifest);
}
async function removeComponentVersion(componentId) {
  const manifest = await readManifest();
  delete manifest[componentId];
  await writeManifest(manifest);
}

// src/flags.ts
var FLAG_TO_PROP = {
  "--color": "color",
  "--density": "density",
  "--charset": "characterSet",
  "--animation": "animation",
  "--duration": "duration"
};
function parseFlags(rawFlags) {
  const props = {};
  for (const raw of rawFlags) {
    const [keyPart, ...valueParts] = raw.split("=");
    const propKey = FLAG_TO_PROP[keyPart];
    if (!propKey) continue;
    if (valueParts.length === 0) {
      props[propKey] = true;
    } else {
      const value = valueParts.join("=");
      props[propKey] = isNaN(Number(value)) ? value : Number(value);
    }
  }
  return props;
}

// src/version.ts
var PACKAGE_VERSION = "0.1.0";

// src/commands/add.ts
async function runAdd(componentId, rawFlags) {
  console.log(pc.bold(`
  forge-ascii add ${componentId}
`));
  const meta = REGISTRY_BY_ID[componentId];
  if (!meta) {
    console.log(pc.red(`  Unknown component: "${componentId}"`));
    console.log(pc.dim("  Run npx @forgelabs-studio/ascii list to see available components.\n"));
    process.exit(1);
  }
  try {
    let config = await readConfig();
    if (!config) {
      config = createDefaultConfig();
      console.log(pc.dim("  No ascii config found in forge.config.json - creating one.\n"));
    }
    const props = parseFlags(rawFlags);
    await generateComponent(componentId, meta.displayName, props, config);
    config.components[componentId] = props;
    await writeConfig(config);
    await setComponentVersion(componentId, PACKAGE_VERSION);
    console.log(pc.green("  \u2713") + ` ${meta.displayName}.tsx`);
    console.log(pc.green("  \u2713") + ` ${meta.displayName}.css`);
    console.log(pc.dim(`
  Import with:`));
    console.log(pc.cyan(`  import { ${meta.displayName} } from '@/components/forge/${meta.displayName}'
`));
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc.red(`
  \u2716 Failed to add ${componentId}: ${message}
`));
    process.exit(1);
  }
}

// src/commands/list.ts
import pc2 from "picocolors";
async function runList() {
  console.log(pc2.bold("\n  FORGE.ascii components\n"));
  const config = await readConfig();
  const installed = new Set(Object.keys(config?.components ?? {}));
  for (const component of REGISTRY) {
    const tick = installed.has(component.id) ? pc2.green("\u2713") : pc2.dim("\u25CB");
    console.log(`  ${tick} ${pc2.white(component.displayName.padEnd(24))} ${pc2.dim(component.description)}`);
  }
  console.log();
}

// src/commands/update.ts
import pc3 from "picocolors";
async function runUpdate(componentId) {
  console.log(pc3.bold(`
  forge-ascii update ${componentId}
`));
  try {
    const config = await readConfig();
    if (!config) {
      console.log(pc3.red("  No forge.config.json found.\n"));
      process.exit(1);
    }
    const meta = REGISTRY_BY_ID[componentId];
    if (!meta) {
      console.log(pc3.red(`  Unknown component: "${componentId}"
`));
      process.exit(1);
    }
    const props = config.components[componentId] ?? {};
    await generateComponent(componentId, meta.displayName, props, config);
    config.components[componentId] = props;
    await writeConfig(config);
    console.log(pc3.green("  \u2713") + ` ${meta.displayName} regenerated
`);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc3.red(`
  \u2716 Failed to update ${componentId}: ${message}
`));
    process.exit(1);
  }
}

// src/commands/remove.ts
import fs4 from "fs-extra";
import path4 from "path";
import pc4 from "picocolors";
async function runRemove(componentId) {
  console.log(pc4.bold(`
  forge-ascii remove ${componentId}
`));
  try {
    const config = await readConfig();
    if (!config) {
      console.log(pc4.red("  No forge.config.json found.\n"));
      process.exit(1);
    }
    const meta = REGISTRY_BY_ID[componentId];
    if (!meta) {
      console.log(pc4.red(`  Unknown component: "${componentId}"
`));
      process.exit(1);
    }
    const outputDir = path4.join(process.cwd(), config.output);
    const tsxPath = path4.join(outputDir, `${meta.displayName}.tsx`);
    const cssPath = path4.join(outputDir, `${meta.displayName}.css`);
    if (await fs4.pathExists(tsxPath)) {
      await fs4.remove(tsxPath);
      console.log(pc4.red("  \u2715") + ` ${meta.displayName}.tsx`);
    }
    if (await fs4.pathExists(cssPath)) {
      await fs4.remove(cssPath);
      console.log(pc4.red("  \u2715") + ` ${meta.displayName}.css`);
    }
    delete config.components[componentId];
    await writeConfig(config);
    await removeComponentVersion(componentId);
    console.log(pc4.dim("\n  Removed from forge.config.json.\n"));
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc4.red(`
  \u2716 Failed to remove ${componentId}: ${message}
`));
    process.exit(1);
  }
}

// src/commands/check.ts
import pc5 from "picocolors";
import semver from "semver";
var PACKAGE_NAME = "@forgelabs-studio/ascii";
async function fetchLatestVersion() {
  const res = await fetch(`https://registry.npmjs.org/${PACKAGE_NAME}/latest`);
  if (!res.ok) throw new Error(`npm registry returned ${res.status}`);
  const data = await res.json();
  return data.version;
}
async function runCheck() {
  console.log(pc5.bold("\n  forge-ascii check\n"));
  try {
    const manifest = await readManifest();
    const installed = Object.entries(manifest);
    if (installed.length === 0) {
      console.log(pc5.dim("  No components installed. Run npx @forgelabs-studio/ascii add ascii to get started.\n"));
      return;
    }
    console.log(pc5.dim("  Checking latest version on npm...\n"));
    const latest = await fetchLatestVersion();
    let allUpToDate = true;
    for (const [componentId, installedVersion] of installed) {
      const isOutdated = semver.lt(installedVersion, latest);
      if (isOutdated) {
        allUpToDate = false;
        console.log(
          `  ${pc5.yellow("!")} ${pc5.white(componentId.padEnd(20))} ${pc5.dim(installedVersion)} -> ${pc5.cyan(latest)}`
        );
      } else {
        console.log(
          `  ${pc5.green("\u2713")} ${pc5.white(componentId.padEnd(20))} ${pc5.dim(installedVersion)}`
        );
      }
    }
    if (!allUpToDate) {
      console.log(pc5.dim("\n  Update with: npx @forgelabs-studio/ascii update <component>\n"));
    } else {
      console.log(pc5.dim("\n  All components are up to date.\n"));
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc5.red(`
  \u2716 Check failed: ${message}
`));
    process.exit(1);
  }
}

// src/index.ts
var program = new Command();
program.name("forge-ascii").description("FORGE.ascii - image-to-ASCII-art component generator for React").version(PACKAGE_VERSION);
program.command("add <component>").description("Add the ascii component").allowUnknownOption(true).action((component, _opts, cmd) => {
  const rawFlags = cmd.args.slice(1);
  runAdd(component, rawFlags);
});
program.command("list").description("List all available and installed components").action(() => runList());
program.command("update <component>").description("Regenerate a component using its saved configuration").action((component) => runUpdate(component));
program.command("remove <component>").description("Remove a component and its files").action((component) => runRemove(component));
program.command("check").description("Check installed components against the latest published version").action(() => runCheck());
program.parse();
